script:
frappe.ui.form.on('Administrative Letter', {
    onload: function(frm) {
        if (frm.is_new()) {
            auto_fill_sender(frm);
        }
    },
    refresh: function(frm) {
        if (frm.is_new()) {
            auto_fill_sender(frm);
        }
    },
    letter_type: function(frm) {
        if (!frm.doc.letter_type) {
            frm.set_value('letter_body', '');
            return;
        }
        frappe.call({
            method: 'frappe.client.get',
            args: {
                doctype: 'Letter Template',
                name: frm.doc.letter_type
            },
            callback: function(r) {
                if (r.message) {
                    let body = r.message.letter_body || '';
                    body = replace_vars(frm, body);
                    frm.set_value('letter_body', body);
                }
            }
        });
    },
    sender_name: function(frm) { refresh_body(frm); },
    recipient_name: function(frm) { refresh_body(frm); },
    letter_date: function(frm) { refresh_body(frm); },
    sender_department: function(frm) { refresh_body(frm); },
    recipient_department: function(frm) { refresh_body(frm); }
});

function auto_fill_sender(frm) {
    frm.set_value('sender_user', frappe.session.user);
    frappe.call({
        method: 'frappe.client.get',
        args: {
            doctype: 'User',
            name: frappe.session.user,
            fields: ['full_name', 'department']
        },
        callback: function(r) {
            if (r.message) {
                frm.set_value('sender_name', r.message.full_name);
                if (r.message.department) {
                    frm.set_value('sender_department', r.message.department);
                }
            }
        }
    });
    frm.set_value('letter_date', frappe.datetime.get_today());
}

function replace_vars(frm, text) {
    let replacements = {
        '{{sender_name}}':          frm.doc.sender_name || '',
        '{{recipient_name}}':       frm.doc.recipient_name || '',
        '{{letter_date}}':          frm.doc.letter_date || '',
        '{{sender_department}}':    frm.doc.sender_department || '',
        '{{recipient_department}}': frm.doc.recipient_department || '',
        '{{reference_number}}':     frm.doc.reference_number || '',
        '{{letter_title}}':        frm.doc.letter_title || '',
    };
    for (let key in replacements) {
        text = text.split(key).join(replacements[key]);
    }
    return text;
}

function refresh_body(frm) {
    if (!frm.doc.letter_type) return;
    frappe.call({
        method: 'frappe.client.get',
        args: {
            doctype: 'Letter Template',
            name: frm.doc.letter_type
        },
        callback: function(r) {
            if (r.message) {
                let body = replace_vars(frm, r.message.letter_body || '');
                frm.set_value('letter_body', body);
            }
        }
    });
}

frappe.ui.form.on('Administrative Letter', {
    refresh: function(frm) {
        // 1. إدارة ظهور الأزرار الإجرائية بعد الاعتماد والـ Submit (docstatus === 1)
        if (frm.doc.docstatus === 1) {
            
            // زر "تأكيد استلام المراسلة" (تعديل دالة الحفظ لضمان عدم التراجع)
            if (frm.doc.status === 'مرسلة' && (frappe.session.user === frm.doc.recipient_email || frappe.session.user === 'Administrator')) {
                frm.add_custom_button(__('تأكيد استلام المراسلة'), function() {
                    
                    // التعديل المباشر في قاعدة البيانات والسيرفر لتفادي مشكلة زر Update والرفض
                    frappe.call({
                        method: 'frappe.client.set_value',
                        args: {
                            doctype: 'Administrative Letter',
                            name: frm.doc.name,
                            fieldname: 'status',
                            value: 'مستلمة'
                        },
                        callback: function() {
                            // إعادة تحميل المستند ليعكس الشارة والألوان الجديدة فوراً وثباتها
                            frm.reload_doc();
                            frappe.show_alert({message: __('تم تأكيد استلام المراسلة بنجاح وتحديث الحالة'), indicator: 'green'});
                        }
                    });
                    
                }).addClass('btn-primary'); 
            }

            // زر "أرشفة المراسلة" (تعديل دالة الحفظ لضمان عدم التراجع)
            if (frm.doc.status === 'مستلمة' && (frappe.session.user === frm.doc.owner || frappe.session.user === 'Administrator')) {
                frm.add_custom_button(__('نقل إلى الأرشيف الإداري'), function() {
                    frappe.confirm(__('هل أنت متأكد من أرشفة هذه المراسلة الإدارية؟'), function() {
                        
                        // التعديل المباشر في قاعدة البيانات للأرشفة
                        frappe.call({
                            method: 'frappe.client.set_value',
                            args: {
                                doctype: 'Administrative Letter',
                                name: frm.doc.name,
                                fieldname: 'status',
                                value: 'مؤرشفة'
                            },
                            callback: function() {
                                frm.reload_doc();
                                frappe.show_alert({message: __('تمت أرشفة المستند بنجاح'), indicator: 'orange'});
                            }
                        });
                        
                    });
                }).addClass('btn-danger'); 
            }
        }
    }
});

// ربط شارة الحالة العلوية وفي القائمة الخارجية معاً بامتياز وثبات
frappe.listview_settings['Administrative Letter'] = {
    get_indicator: function(doc) {
        if (doc.status === 'مرسلة') {
            return [__("مرسلة"), "orange", "status,=,مرسلة"];
        } else if (doc.status === 'مستلمة') {
            return [__("مستلمة"), "green", "status,=,مستلمة"];
        } else if (doc.status === 'مؤرشفة') {
            return [__("مؤرشفة"), "gray", "status,=,مؤرشفة"];
        } else {
            return [__("مسودة"), "red", "status,=,مسودة"];
        }
    }
};
